#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        long long N, X; scanf("%lld %lld", &N, &X);
        long long cost = 0; int prev = 0;
        for(long long i = 0; i < N; ++i){
            int d; scanf("%d", &d);
            if(d == 1 || prev == 1) cost += X;
            prev = d;
        }
        printf("%lld", cost);
        if(T) printf("\n");
    }
    return 0;
}

